INSERT INTO kb_entries (id, workspace_id, type, category, title, content, keywords, modes, priority, is_active, metadata_json, created_at, updated_at)
VALUES ('f01d5ca7-a182-4984-b762-cc95c1656e63', 'default', 'block', 'general', 'Proofs & Track Record', '--- 150+ Projects Since 2008 ---
Beroperasi sejak 2008 dengan 150+ project yang berhasil diselesaikan di seluruh Indonesia.

--- Case Study Metrics ---
Hasil terukur: 70% peningkatan efisiensi operasional, 99% akurasi finansial, 60% lebih cepat dari timeline tradisional.

--- Client Testimonials ---
Peningkatan lead generation dari website, masalah hardware downtime turun drastis, warna cetak presisi.

--- Technology Stack ---
React, Next.js, Astro.js, Node.js, Laravel, Python, PostgreSQL, MongoDB, Flutter, Docker, AWS, Sanity CMS.', 'sejak 2008, 150 project, pengalaman, track record, testimonial, tech stack, React, Next.js, case study, metrik, hasil terukur, ROI, Indonesia', '', 8, 1, NULL, '2026-06-15T22:28:39.080993Z', '2026-06-15T22:28:39.080993Z');
INSERT INTO kb_entries (id, workspace_id, type, category, title, content, keywords, modes, priority, is_active, metadata_json, created_at, updated_at)
VALUES ('6902f03f-e221-45f5-a436-8f52073aec74', 'default', 'block', 'general', 'Value Propositions', '--- Unified Vendor Management ---
Satu partner terpercaya untuk semua kebutuhan digital dan cetak. Mengurangi friksi koordinasi.

--- End-to-End Support ---
"Dari build sampai pendampingan" - Kotacom mendampingi setelah peluncuran dengan maintenance dan support berkelanjutan.

--- Integrated Online & Offline ---
Infrastruktur online (website, software) dan offline (percetakan, IT hardware) berjalan sejalan dan terintegrasi.

--- Jargon-Free Communication ---
Komunikasi jelas tanpa jargon teknis. Project planning transparan dengan timeline dan milestone.

--- No Hidden Costs ---
Semua biaya diinformasikan di awal sebelum pekerjaan dimulai.', 'value prop, unified vendor, satu partner, end-to-end, pendampingan, online offline, integrasi, jargon-free, no hidden cost, efisiensi, terpadu', '', 8, 1, NULL, '2026-06-15T22:28:39.080993Z', '2026-06-15T22:28:39.080993Z');
INSERT INTO kb_entries (id, workspace_id, type, category, title, content, keywords, modes, priority, is_active, metadata_json, created_at, updated_at)
VALUES ('891613da-1e6b-4902-945b-379d7fac62df', 'default', 'block', 'general', 'Company Information', '--- Pricing Overview ---
